using System;
using Microsoft.Xna.Framework;
using Microsoft.Xna.Framework.Graphics;

namespace Apos.Shapes {
    /// <summary>
    /// A 64x64 void-and-cluster blue noise tile (Ulichney 1993, torus-wrapped, sigma 1.9) used to
    /// dither gradients. Every byte value appears exactly 16 times so the dither stays unbiased.
    /// Baked at authoring time because blue noise is too expensive to synthesize at runtime.
    /// </summary>
    internal static class BlueNoise {
        public const int Size = 64;

        public static Texture2D CreateTexture(GraphicsDevice graphicsDevice) {
            byte[] values = Convert.FromBase64String(Data);
            var pixels = new Color[values.Length];
            for (int i = 0; i < values.Length; i++) {
                pixels[i] = new Color(values[i], values[i], values[i], values[i]);
            }
            var texture = new Texture2D(graphicsDevice, Size, Size, false, SurfaceFormat.Color);
            texture.SetData(pixels);
            return texture;
        }

        private const string Data = "";
    }
}
